mapper.select:
SELECT COUNT(*) 
FROM equipment_borrow 
WHERE user_id = #{userId} 
AND equipment_id = #{equipmentId}
AND borrow_status = 1
AND NOT EXISTS (SELECT 1 FROM equipment_return er WHERE er.borrow_id = equipment_borrow.id AND er.return_status = 1 AND er.audit_result != '报修通过自动归还')

SELECT COUNT(*) 
FROM equipment_borrow 
WHERE user_id = #{userId} 
AND equipment_id = #{equipmentId}
AND audit_status = 0

SELECT COUNT(*) 
FROM equipment_repair 
WHERE equipment_id = #{equipmentId} 
AND user_id = #{userId}
AND repair_status = 1

SELECT COALESCE(SUM(
    borrow_quantity - COALESCE((
        SELECT SUM(er.repair_quantity) 
        FROM equipment_return er 
        WHERE er.borrow_id = equipment_borrow.id 
        AND er.return_status = 1
        AND er.repair_quantity IS NOT NULL
    ), 0)
), 0)
FROM equipment_borrow
WHERE equipment_id = #{equipmentId}
AND user_id = #{userId}
AND borrow_status = 1

SELECT COUNT(*) 
FROM equipment_borrow 
WHERE equipment_id = #{equipmentId} 
AND user_id = #{userId}
AND borrow_status = 1
AND NOT EXISTS (SELECT 1 FROM equipment_return er WHERE er.borrow_id = equipment_borrow.id AND er.return_status = 1 AND er.audit_result != '报修通过自动归还')

SELECT b.id, b.equipment_id, b.equipment_number, b.equipment_name, COALESCE(b.equipment_model, e.equipment_model) AS equipment_model, COALESCE(b.equipment_image, e.equipment_image) AS equipment_image, b.equipment_type_id, et.type_name AS equipment_type, b.user_id, u.real_name AS real_name, u.phone AS phone, b.borrow_quantity + COALESCE((SELECT SUM(er.return_quantity) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1), 0) AS original_quantity, b.borrow_quantity, COALESCE((SELECT SUM(er.return_quantity) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1), 0) AS return_quantity, b.borrow_time, b.expected_return_time, b.purpose, b.borrow_status, b.audit_status, b.audit_user_id, bu.real_name AS audit_user_name, b.audit_time, b.audit_result, b.reserve_id, b.create_time, b.update_time, (SELECT COUNT(*) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1) AS has_return, (SELECT COUNT(*) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1 AND er.audit_result = '报修通过自动归还') AS has_repair_return FROM equipment_borrow b LEFT JOIN equipment e ON b.equipment_id = e.id LEFT JOIN equipment_type et ON e.equipment_type_id = et.id LEFT JOIN sys_user u ON b.user_id = u.id LEFT JOIN sys_user bu ON b.audit_user_id = bu.id
AND b.user_id = #{userId}
AND b.borrow_status = 1 AND (SELECT COUNT(*) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1) = 0 AND (b.expected_return_time IS NULL OR b.expected_return_time > NOW())
AND b.borrow_status = 1 AND (SELECT COUNT(*) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1) = 0 AND b.expected_return_time IS NOT NULL AND b.expected_return_time < NOW()
AND (SELECT COUNT(*) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1) > 0
AND b.borrow_status = #{status}
AND b.audit_status = #{auditStatus}
AND (b.equipment_name LIKE CONCAT('%', #{keyword}, '%') OR b.equipment_number LIKE CONCAT('%', #{keyword}, '%') OR u.real_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY b.create_time DESC

SELECT b.id, b.equipment_id, b.equipment_number, b.equipment_name, COALESCE(b.equipment_model, e.equipment_model) AS equipment_model, COALESCE(b.equipment_image, e.equipment_image) AS equipment_image, b.equipment_type_id, et.type_name AS equipment_type, b.user_id, u.real_name AS real_name, u.phone AS phone, b.borrow_quantity + COALESCE((SELECT SUM(er.return_quantity) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1), 0) AS original_quantity, b.borrow_quantity, COALESCE((SELECT SUM(er.return_quantity) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1), 0) AS return_quantity, b.borrow_time, b.expected_return_time, b.purpose, b.borrow_status, b.audit_status, b.audit_user_id, bu.real_name AS audit_user_name, b.audit_time, b.audit_result, b.reserve_id, b.create_time, b.update_time, (SELECT COUNT(*) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1) AS has_return, (SELECT COUNT(*) FROM equipment_return er WHERE er.borrow_id = b.id AND er.return_status = 1 AND er.audit_result = '报修通过自动归还') AS has_repair_return FROM equipment_borrow b LEFT JOIN equipment e ON b.equipment_id = e.id LEFT JOIN equipment_type et ON e.equipment_type_id = et.id LEFT JOIN sys_user u ON b.user_id = u.id LEFT JOIN sys_user bu ON b.audit_user_id = bu.id
AND b.equipment_id IN
#{id}
AND b.user_id = #{userId}
AND b.create_time >= #{startTime}
ORDER BY b.create_time DESC LIMIT 1000
